import{_ as t,o as i,c as o,a3 as n}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"107. Midwifery Continuity Of Care Models","description":"","frontmatter":{"title":"107. Midwifery Continuity Of Care Models","eba":"Nurses and Midwives 2024-2028","topics":["preliminary","definitions","staffing"]},"headers":[],"relativePath":"ebas/nurses-midwives/safe-patient-care/107-midwifery-continuity-of-care-models.md","filePath":"ebas/nurses-midwives/safe-patient-care/107-midwifery-continuity-of-care-models.md"}'),a={name:"ebas/nurses-midwives/safe-patient-care/107-midwifery-continuity-of-care-models.md"};function r(s,e,l,p,d,c){return i(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="_107-midwifery-continuity-of-care-models" tabindex="-1">107. Midwifery Continuity Of Care Models <a class="header-anchor" href="#_107-midwifery-continuity-of-care-models" aria-label="Permalink to &quot;107. Midwifery Continuity Of Care Models&quot;">​</a></h1><p><strong>107.1</strong> Safe Patient Care Act</p><p>Nothing in this clause permits variations inconsistent with the minimum ratio requirements prescribed by or made under the Safe Patient Care Act.</p><p><strong>107.2</strong> Definition</p><p><strong>(a)</strong> Local Health Agency Committee (LHAC) means a committee comprising equal numbers of local ANMF representatives and local Employer representatives.</p><p><strong>(b)</strong> Continuity of Care Model includes:</p><p><strong>(i)</strong> Midwifery group practice – caseload;</p><p><strong>(ii)</strong> MAPS – caseload of antenatal, postnatal and domiciliary care provision, provided that the following sub-clauses do not apply to a MAPS model:</p><p><strong>(A)</strong> subclause 107.3(d)(i);</p><p><strong>(B)</strong> clause 107.7A (Commuted loading review); and</p><p><strong>(C)</strong> subclause 107.4(d) (caseload).</p><p><strong>107.3</strong> Introducing a Midwifery Continuity of Care Model</p><p><strong>(a)</strong> An Employer may propose to introduce a Midwifery Continuity of Care Model (Proposal).</p><p><strong>(b)</strong> The Employer will notify:</p><p><strong>(i)</strong> the LHAC; and</p><p><strong>(ii)</strong> the ANMF Secretary in writing.</p><p><strong>(c)</strong> The LHAC will be consulted on the Proposal. Consultation timelines are to be consistent with the indictive timelines in <a href="/eba/ebas/nurses-midwives/consultation-disputes/11-consultation.html">clause 11</a>.</p><p><strong>(d)</strong> The LHAC will be consulted on:</p><p><strong>(i)</strong> flexibility and frequency of on call in relation to EFT/Caseload;</p><p><strong>(ii)</strong> full indemnity arrangements to be maintained by the Employer; and</p><p><strong>(iii)</strong> clinically effective arrangements that are maintained and/or adapted to ensure optimal client outcomes at all times.</p><p><strong>(iv)</strong> The Proposal will ensure that handover to another midwife (which may include a midwife not participating in the model) will be available between 8 and 12 hours of duty.</p><p><a href="/eba/ebas/mental-health/schedules/01-list-of-employers.html">Appendix 1</a> – List of Employers 224</p><p><a href="/eba/ebas/mental-health/schedules/01-list-of-employers.html">Appendix 1</a> – List of Employers</p><p><strong>(v)</strong> Professional development support to be available as per this Agreement, with additional support to be agreed between the Employer and Employee, as required.</p><p><strong>(vi)</strong> Appropriate occupational health and safety provisions, including no lift/violence and aggression/communication/equipment/etc.</p><p><strong>(vii)</strong> The four (4) days clear off duty and on call provided for in this Agreement to apply.</p><p><strong>(e)</strong> Following consultation with the LHAC, the Employer will distribute the Proposal, including any amendments arising from consultation, to affected midwives (including those midwives who may not participate in the model).</p><p><strong>(f)</strong> All proposals must take into account and address the matters set out at clause</p><p><strong>107.4</strong> below.</p><p><strong>(g)</strong> Details of arrangements for midwives not entering the new model will be contained within the Proposal. Whether working in a new model or not, arrangements will be such that midwives can have access with their Employer and be able to perform the range of midwifery duties at an equivalent level to the access and performance provided prior to the implementation of the model in order to maintain their skill base.</p><p><strong>(h)</strong> Any subsequent changes in a Midwifery Continuity of Care Models must only occur following further consultation with the ANMF and affected Employees and in compliance with this clause.</p><p><strong>107.4</strong> Guidelines for Midwifery Continuity of Care Models</p><p>The guidelines for Midwifery Continuity of Care Models are as follows:</p><p><strong>(a)</strong> Models should aim for continuity of care including pregnancy care, labour and birth care, post-natal and community care.</p><p><strong>(b)</strong> Changes to employment patterns (including hours) will be agreed as part of the consideration of a proposal and entitlements will apply in accordance with the new pattern of work (including hours), and this clause 107. For midwives not entering the model, existing work patterns (including hours) and entitlements will continue unless otherwise agreed between the Employer and the midwife.</p><p><strong>(c)</strong> Where the model is not embedded within a full maternity service (i.e. a major regional or metropolitan health service) it is recognised there may not be on-site back up from other suitably qualified and skilled midwives (including midwives not participating in the model). In these circumstances, the LHAC Proposal and consultation must address appropriate back up and support at all times, including the ability to hand over to other suitably qualified and skilled midwives (including midwives not participating in the model). For example, the arrangements should include suitable provisions consistent with the operation of the model to provide back-up, support and relief for circumstances such as meal breaks, emergency assistance, birthing assistance etc.</p><p><strong>(d)</strong> The caseload per one EFT midwife will not exceed 45 women (booked in) per annum, with proportional caseloads to be allocated to part-time midwives.</p><p><strong>(e)</strong> Local arrangements are to be agreed by the LHAC and resourced by the Employer to ensure compliance with this clause.</p><p><strong>(f)</strong> Average full-time day of 8 hours to be the standard objective with an absolute maximum of 12 hours.</p><p><a href="/eba/ebas/mental-health/schedules/01-list-of-employers.html">Appendix 1</a> – List of Employers 225</p><p><a href="/eba/ebas/mental-health/schedules/01-list-of-employers.html">Appendix 1</a> – List of Employers</p><p><strong>(g)</strong> Midwives to be provided with sufficient flexibility to meet client needs in accordance with local arrangements and this clause.</p><p><strong>(h)</strong> Appropriate managerial and midwife classification structure to be included in the model, taking into account the extent and size of the model and its interrelationship with existing maternity services at the local facility, the midwifery career structure and this Agreement.</p><p><strong>(i)</strong> Vehicle provided or relevant vehicle allowance payable.</p><p><strong>(j)</strong> The model will not in any way operate to reduce or preclude the provision of MCH nursing services to clients.</p><p><strong>(k)</strong> The model must clearly and explicitly outline the inter-relationship between the existing maternity services (and, if necessary, existing services related to maternity services) and the proposed model.</p><p><strong>107.5</strong> Remuneration and other entitlements</p><p><strong>(a)</strong> Midwives participating in the Midwifery Continuity of Care Model (other than MAPS) will receive a commuted loading on salary, based on the actual number and pattern of hours worked, in lieu of applicable:</p><p><strong>(i)</strong> public holiday penalties;</p><p><strong>(ii)</strong> Saturday and Sunday penalties;</p><p><strong>(iii)</strong> recall and overtime;</p><p><strong>(iv)</strong> on call allowance;</p><p><strong>(v)</strong> shift allowance;</p><p><strong>(vi)</strong> telephone recall; and</p><p><strong>(vii)</strong> annual leave loading paid as &quot;projected roster&quot;.</p><p><strong>(b)</strong> The commuted loading under this clause is the greater of:</p><p><strong>(i)</strong> 32% of the Employee&#39;s salary; or</p><p><strong>(ii)</strong> if at the time the 2020 Agreement came into effect the Employee receives a commuted loading greater than 32%, that loading.</p><p><strong>(c)</strong> All other entitlements set out in this Agreement will apply.</p><p><strong>(d)</strong> The commuted loading will be paid in addition to the ordinary time rate of pay during all periods of annual leave.</p><p><strong>(e)</strong> Midwives working in the Continuity of Care Model will have a separate roster and are on call for their caseload.</p><p><strong>107.7A</strong> Commuted loading review</p><p>In the first six months of this Agreement, the VHIA, on behalf of the Employers, and the ANMF, on behalf of the Employees, will jointly undertake audits of Employers using Commuted Loading to determine if the percentage loading accurately reflects the following entitlements otherwise payable, recognising that some of the provisions below have changed in this Agreement:</p><p><a href="/eba/ebas/mental-health/schedules/01-list-of-employers.html">Appendix 1</a> – List of Employers 226</p><p><a href="/eba/ebas/mental-health/schedules/01-list-of-employers.html">Appendix 1</a> – List of Employers</p><p><strong>(a)</strong> public holiday penalties;</p><p><strong>(b)</strong> Saturday and Sunday penalties;</p><p><strong>(c)</strong> recall and overtime;</p><p><strong>(d)</strong> on call allowance;</p><p><strong>(e)</strong> shift allowance;</p><p><strong>(f)</strong> telephone recall; and</p><p><strong>(g)</strong> annual leave loading paid as &quot;projected roster&quot;.</p><p>If the review shows that a loading of greater than 32% more properly reflects the above entitlements otherwise payable, the higher rate will be payable effective 1 May 2024. A dispute that cannot be resolved between the ANMF and the VHIA about this review will be managed in accordance with subclause 14.1(e).</p><p><strong>107.7B</strong> Midwives not in the model</p><p>Participation in the model for midwifery staff is voluntary. Subject to operational requirements (e.g. where a midwife has been replaced on the ward whilst participating in the model) midwives will be able to elect to participate/cease participating in the model provided adequate notice is provided. No midwife will lose their job by reason of the introduction of a Continuity of Care Model.</p><p><strong>107.6</strong> Advertising Positions in the Model</p><p>Once a proposal has been implemented by an Employer in accordance with this clause, the Employer will be entitled to advertise for new Employee midwives to participate exclusively in the model(s) and subclause 107.7(a) above will not apply, i.e. the newly employed midwives would not be able to elect to cease participating in the model.</p><p><strong>107.7</strong> Evaluation</p><p><strong>(a)</strong> Where a Midwifery Continuity of Care Model is introduced, nursing/midwifery management, ANMF nominated representatives and relevant staff will:</p><p><strong>(i)</strong> during the first 12 months conduct an informal review on a monthly basis; and</p><p><strong>(ii)</strong> no later than 12 months after the introduction of the model, conduct a comprehensive formal review with further reviews at agreed intervals thereafter.</p><p><strong>107.8</strong> Ward shifts for midwives employed in a Midwifery Continuity of Care Model</p><p>For the purpose of <a href="/eba/ebas/nurses-midwives/allowances/41A-change-of-ward-allowance.html">clause 41A</a>, the Continuity of Care model will be considered the Employee’s Base Ward.</p><p><strong>107.9</strong> Dispute Resolution</p><p><strong>(a)</strong> In the event of any dispute arising between an Employer and the ANMF relating to the continuation or implementation of midwifery continuity of care models, the review at clause 107.7 above, and this clause, it will in the first instance be referred to the ANMF/VHIA/DOH for consideration and consultation.</p><p><strong>(b)</strong> In the event the dispute is unable to be resolved in accordance with subclause 107.9(a) above, it will be processed as a collective dispute in accordance with the Dispute Resolution Procedure of this Agreement.</p><p><a href="/eba/ebas/mental-health/schedules/01-list-of-employers.html">Appendix 1</a> – List of Employers 227</p><p>Plain language terms: caseload midwifery, continuity midwifery, CoC.</p>',89)])])}const g=t(a,[["render",r]]);export{m as __pageData,g as default};
